// app/sejours-enfants-ados/SejoursClient.jsx
"use client";
import { useState } from "react";
import Link from "next/link";
import {
  MapPin, Calendar, Users, Clock, Search, X, SunMedium,
  Snowflake, Flower2, Globe, Heart, ChevronDown, ArrowRight, Leaf
} from "lucide-react";

const C = {
  yellow:  "#FFC801",
  saffron: "#FF9932",
  teal:    "#114C5A",
  tealMid: "#1A6B7C",
  lilac:   "#EFDEF9",
  arctic:  "#F1F6F4",
  white:   "#ffffff",
};

/* ─── UTILS ─── */
const getSeasonConfig = (saison) => {
  switch (saison?.toLowerCase()) {
    case 'automne':   return { icon: Leaf, color: C.saffron };
    case 'hiver':     return { icon: Snowflake, color: "#7dd3fc" };
    case 'printemps': return { icon: Flower2, color: "#10b981" };
    case 'été':       return { icon: SunMedium, color: C.yellow };
    default:          return { icon: Globe, color: C.teal };
  }
};

const formatAge = (age) => {
  if (!age) return "Tous âges";
  const str = age.toLowerCase();
  if (str.includes("ans") || str.includes("sénior") || str.includes("senior")) return age;
  return `${age} ans`;
};

const formatSejourDates = (startStr, endStr) => {
  if (!startStr) return "Dates à définir";
  const start = new Date(startStr);
  if (!endStr) return start.toLocaleDateString("fr-FR");
  const end = new Date(endStr);
  const mois = ['Janvier', 'Février', 'Mars', 'Avril', 'Mai', 'Juin', 'Juillet', 'Août', 'Septembre', 'Octobre', 'Novembre', 'Décembre'];
  if (start.getMonth() === end.getMonth()) return `Du ${start.getDate()} au ${end.getDate()} ${mois[start.getMonth()]}`;
  return `Du ${start.getDate()} ${mois[start.getMonth()]} au ${end.getDate()} ${mois[end.getMonth()]}`;
};

const getDuree = (startStr, endStr) => {
  if (!startStr || !endStr) return "À définir";
  const diffDays = Math.ceil(Math.abs(new Date(endStr) - new Date(startStr)) / (1000 * 60 * 60 * 24)) + 1;
  return diffDays === 1 ? "1 jour" : `${diffDays} jours`;
};

const matchCategory = (s, cat) => {
  if (cat === "tous") return true;
  const ageStr = (s.tranchesAge || "").toLowerCase();
  if (cat === "seniors" && (ageStr.includes("senior"))) return true;
  if (cat === "ados" && (ageStr.includes("13") || ageStr.includes("14") || ageStr.includes("15") || ageStr.includes("16") || ageStr.includes("17"))) return true;
  if (cat === "enfants") return !ageStr.includes("senior") && !ageStr.includes("13") && ageStr !== "";
  return false;
};

/* ─── COMPOSANTS ─── */
function SejourCard({ s, idx }) {
  const [hovered, setHovered] = useState(false);
  const { icon: Icon, color: sColor } = getSeasonConfig(s.saison);

  return (
    <Link href={`/sejours-enfants-ados/${s.id}`} style={{ textDecoration: "none" }}
      onMouseEnter={() => setHovered(true)} onMouseLeave={() => setHovered(false)}>
      <div style={{
        background: C.white, borderRadius: "24px", overflow: "hidden", 
        transform: hovered ? "translateY(-6px)" : "translateY(0)",
        boxShadow: hovered ? "0 20px 56px rgba(17,76,90,0.14)" : "0 2px 16px rgba(17,76,90,0.07)",
        transition: "all .3s ease", display: "flex", flexDirection: "column"
      }}>
        <div style={{ position: "relative", height: "200px", overflow: "hidden" }}>
          <img src={s.imageUrl || "https://images.unsplash.com/photo-1507525428034-b723cf961d3e?w=800"} alt={s.titre} style={{ width: "100%", height: "100%", objectFit: "cover", transform: hovered ? "scale(1.05)" : "scale(1)", transition: "transform .5s ease" }} />
          <div style={{ position: "absolute", top: "12px", left: "12px", background: "rgba(255,255,255,0.9)", backdropFilter: "blur(6px)", borderRadius: "999px", padding: "4px 10px", display: "flex", alignItems: "center", gap: "5px" }}>
            <Icon size={10} style={{ color: sColor }} />
            <span style={{ fontSize: "10px", fontWeight: 800, color: C.teal, textTransform: "uppercase" }}>{s.saison}</span>
          </div>
          <div style={{ position: "absolute", bottom: "12px", right: "12px", background: C.yellow, borderRadius: "999px", padding: "3px 10px", display: "flex", alignItems: "center", gap: "4px" }}>
            <Clock size={9} style={{ color: C.teal }} />
            <span style={{ fontSize: "10px", fontWeight: 700, color: C.teal }}>{getDuree(s.dateDebut, s.dateFin)}</span>
          </div>
        </div>
        <div style={{ padding: "18px 20px 20px" }}>
          <div style={{ display: "flex", justifyContent: "space-between", gap: "8px", marginBottom: "12px" }}>
            <h3 style={{ fontSize: "14px", fontWeight: 800, color: C.teal, margin: 0 }}>{s.titre}</h3>
            <span style={{ fontSize: "15px", fontWeight: 900, color: C.saffron }}>{s.prix}€</span>
          </div>
          <div style={{ display: "flex", flexDirection: "column", gap: "6px", marginBottom: "16px" }}>
            <div style={{ display: "flex", alignItems: "center", gap: "6px", fontSize: "11px", color: "#8aa", fontWeight: 600 }}>
              <Calendar size={12} style={{ color: C.saffron }} /> {formatSejourDates(s.dateDebut, s.dateFin)}
            </div>
            <div style={{ display: "flex", alignItems: "center", gap: "6px", fontSize: "11px", color: "#8aa", fontWeight: 600 }}>
              <MapPin size={12} style={{ color: "#10b981" }} /> {s.lieu}
            </div>
            <div style={{ display: "flex", alignItems: "center", gap: "6px", fontSize: "11px", color: "#8aa", fontWeight: 600 }}>
              <Users size={12} style={{ color: C.teal }} /> {formatAge(s.tranchesAge)}
            </div>
          </div>
          <div style={{ width: "100%", background: hovered ? C.yellow : C.teal, color: hovered ? C.teal : "white", fontSize: "11px", fontWeight: 800, textTransform: "uppercase", borderRadius: "999px", padding: "10px", textAlign: "center", transition: "all .2s" }}>
            Voir le séjour
          </div>
        </div>
      </div>
    </Link>
  );
}

export default function SejoursClient({ sejoursFromDb }) {
  const [cat, setCat] = useState("tous");
  const [search, setSearch] = useState("");

  const filtered = sejoursFromDb?.filter(s => s.statut === "Publié").filter(s => {
    return matchCategory(s, cat) && (!search || s.titre.toLowerCase().includes(search.toLowerCase()) || s.lieu?.toLowerCase().includes(search.toLowerCase()));
  }) || [];

  return (
    <div style={{ background: C.arctic, minHeight: "100vh", padding: "40px 0" }}>
      <div style={{ maxWidth: "1320px", margin: "0 auto", padding: "0 32px" }}>
        
        {/* Filtres et Recherche */}
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "48px", flexWrap: "wrap", gap: "24px" }}>
          <div style={{ display: "flex", gap: "8px", background: "white", padding: "6px", borderRadius: "100px", boxShadow: "0 4px 12px rgba(0,0,0,0.05)" }}>
            {["tous", "enfants", "ados", "seniors"].map(tab => (
              <button key={tab} onClick={() => setCat(tab)} style={{
                padding: "10px 24px", borderRadius: "100px", border: "none", fontSize: "13px", fontWeight: 700, cursor: "pointer",
                background: cat === tab ? C.teal : "transparent", color: cat === tab ? "white" : C.teal, transition: "all .3s"
              }}>{tab.charAt(0).toUpperCase() + tab.slice(1)}</button>
            ))}
          </div>
          <div style={{ position: "relative", width: "100%", maxWidth: "300px" }}>
            <Search size={18} style={{ position: "absolute", left: "16px", top: "50%", transform: "translateY(-50%)", color: "#aaa" }} />
            <input type="text" placeholder="Rechercher..." value={search} onChange={(e) => setSearch(e.target.value)}
              style={{ width: "100%", padding: "12px 16px 12px 44px", borderRadius: "100px", border: "1px solid #e2e8f0", fontSize: "14px" }} />
          </div>
        </div>

        {/* Grille de séjours */}
        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(280px, 1fr))", gap: "24px" }}>
          {filtered.map((s, i) => <SejourCard key={s.id} s={s} idx={i} />)}
        </div>

        {filtered.length === 0 && (
          <div style={{ textAlign: "center", padding: "100px 0", color: "#aaa" }}>
            <Globe size={48} style={{ marginBottom: "16px", opacity: 0.3 }} />
            <p>Aucun séjour trouvé dans cette catégorie.</p>
          </div>
        )}
      </div>
    </div>
  );
}